#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int* A = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        while (Q--) {
            int L, R;
            scanf("%d %d", &L, &R);
            L--; R--;
            int g = 0;
            for (int i = 0; i < L; i++) {
                if (g == 0) g = A[i];
                else g = gcd(g, A[i]);
            }
            for (int i = R + 1; i < N; i++) {
                if (g == 0) g = A[i];
                else g = gcd(g, A[i]);
            }
            printf("%d\n", g);
        }
        free(A);
    }
    return 0;
}

