import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                L--; R--;
                int g = 0;
                for (int i = 0; i < L; i++) {
                    if (g == 0) g = A[i];
                    else g = gcd(g, A[i]);
                }
                for (int i = R + 1; i < N; i++) {
                    if (g == 0) g = A[i];
                    else g = gcd(g, A[i]);
                }
                System.out.println(g);
            }
        }
    }
}

